    toggleFab(false);
    fetchBuckets();
}

function closeBucketManager() {
    document.getElementById('bucket-manager-overlay').classList.remove('active');
    toggleFab(true);
    storageCurrentBucket = null;
    storageCurrentPath = [];
}

async function fetchBuckets() {
    const container = document.getElementById('storage-content');
    container.innerHTML = '<div style="padding:40px; text-align:center; color:var(--ai-accent);">Scanning Buckets...</div>';
    document.getElementById('storage-title').innerText = "Storage Buckets";
    document.getElementById('storage-breadcrumbs').style.display = 'none';
    document.getElementById('btn-storage-upload').style.display = 'none';
    document.getElementById('storage-footer').style.display = 'none';

    try {
        const res = await fetch(CONFIG.funcUrl, { method: 'POST', headers: {'Content-Type': 'application/json'}, body: apiBody({ action: 'list_buckets' }) });
        const data = await res.json();

        if(!data.buckets || data.buckets.length === 0) {
            container.innerHTML = '<div style="padding:40px; text-align:center; color:#666;">No buckets found.</div>';
            return;
        }

        container.innerHTML = data.buckets.map(b => `
            <div class="model-item" onclick="openBucket('${b.name}')" style="cursor:pointer;">
                <div style="display:flex; align-items:center; gap:12px;">
                    <span style="font-size:18px;">${b.public ? '🌍' : '🔒'}</span>
                    <div style="display:flex; flex-direction:column;">
                        <span style="font-weight:600; color:#eee;">${b.name}</span>
                        <small style="color:#555; font-size:9px;">ID: ${b.id}</small>
                    </div>
                </div>
                <span style="color:#444;">📁</span>
            </div>
        `).join('');
    } catch(e) { container.innerHTML = `<div style="color:var(--danger); padding:20px;">${e.message}</div>`; }
}

function openBucket(name) {
    storageCurrentBucket = name;
    storageCurrentPath = [];
    fetchStorageObjects();
}

async function fetchStorageObjects() {
    const container = document.getElementById('storage-content');
    const bread = document.getElementById('storage-breadcrumbs');
    container.innerHTML = '<div style="padding:40px; text-align:center; color:var(--ai-accent);">Reading Objects...</div>';

    document.getElementById('storage-title').innerText = storageCurrentBucket;
    bread.style.display = 'block';
    bread.innerHTML = `<span onclick="fetchBuckets()" style="cursor:pointer; color:var(--primary);">buckets</span> / ` + 
        storageCurrentPath.map((p, i) => `<span onclick="navigateToStorageDepth(${i})" style="cursor:pointer; color:var(--primary);">${p}</span>`).join(' / ');

    document.getElementById('btn-storage-upload').style.display = 'block';
    document.getElementById('storage-footer').style.display = 'flex';

    try {
        const path = storageCurrentPath.join('/');
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'list_storage_objects', bucket: storageCurrentBucket, path: path })
        });
        const data = await res.json();
        storageObjects = data.objects || [];
        renderStorageList();
    } catch(e) { container.innerHTML = `<div style="color:var(--danger); padding:20px;">${e.message}</div>`; }
}

function renderStorageList() {
    const container = document.getElementById('storage-content');
    if(storageObjects.length === 0) {
        container.innerHTML = '<div style="padding:40px; text-align:center; color:#444;">Folder is empty.</div>';
        return;
    }

    container.innerHTML = storageObjects.map((obj, i) => {
        const isFolder = !obj.id;
        const icon = isFolder ? '📁' : '📄';
        return `
            <div class="file-item" style="padding:10px;">
                <div style="display:flex; align-items:center; gap:10px; flex:1; cursor:pointer; min-width:0;" onclick="${isFolder ? `enterStorageFolder('${obj.name}')` : ''}">
                    <span style="font-size:16px;">${icon}</span>
                    <div style="flex:1; min-width:0;">
                        <div style="font-size:12px; color:#eee; white-space:nowrap; overflow:hidden; text-overflow:ellipsis;">${obj.name}</div>
                        ${!isFolder ? `<small style="color:#555; font-size:9px;">${formatBytes(obj.metadata?.size)} • ${obj.metadata?.mimetype}</small>` : ''}
                    </div>
                </div>
                <div class="flex-gap">
                    <input type="checkbox" class="storage-check" data-index="${i}" onchange="updateStorageSelectionCount()" style="accent-color:var(--ai-accent);">
                </div>
            </div>`;
    }).join('');
    updateStorageSelectionCount();
}

function enterStorageFolder(name) {
    storageCurrentPath.push(name);
    fetchStorageObjects();
}

function navigateToStorageDepth(index) {
    storageCurrentPath = storageCurrentPath.slice(0, index + 1);
    fetchStorageObjects();
}

function updateStorageSelectionCount() {
    const count = document.querySelectorAll('.storage-check:checked').length;
    document.getElementById('storage-selection-count').innerText = `${count} items selected`;
}

function toggleAllStorage(force) {
    document.querySelectorAll('.storage-check').forEach(cb => cb.checked = force);
    updateStorageSelectionCount();
}

async function handleStorageUpload(input) {
    const file = input.files[0];
    if(!file) return;

    showGlobalToast("Uploading to " + storageCurrentBucket + "...");
    const reader = new FileReader();
    reader.onload = async (e) => {
        const base64 = e.target.result.split(',')[1];
        const path = (storageCurrentPath.length > 0 ? storageCurrentPath.join('/') + '/' : '') + file.name;
        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'upload_storage_object', bucket: storageCurrentBucket, path, file_body: base64, file_type: file.type })
            });
            const data = await res.json();
            if(data.error) throw new Error(data.error);
            showGlobalToast("✅ Uploaded Successfully");
            fetchStorageObjects();
        } catch(err) { showGlobalToast(err.message, true); }
    };
    reader.readAsDataURL(file);
}

async function deleteSelectedStorage() {
    const checked = Array.from(document.querySelectorAll('.storage-check:checked'));
    if(checked.length === 0) return;

    if(!confirm(`Delete ${checked.length} items? This cannot be undone.`)) return;

    const paths = checked.map(cb => {
        const obj = storageObjects[cb.dataset.index];
        return (storageCurrentPath.length > 0 ? storageCurrentPath.join('/') + '/' : '') + obj.name;
    });

    showGlobalToast("Deleting from " + storageCurrentBucket + "...");
    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'delete_storage_objects', bucket: storageCurrentBucket, paths })
        });
        const data = await res.json();
        if(data.error) throw new Error(data.error);
        showGlobalToast("✅ Deleted");
        fetchStorageObjects();
    } catch(err) { showGlobalToast(err.message, true); }
}

