2237 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2238 |     function applyLocalPatch(content, ops) {
2239 |         let lines = content.split('\n');
2240 |         let logs = [];
2241 |         let success = true;
2242 | 
2243 |         if (typeof ops === 'string') {
2244 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2245 |         }
2246 | 
2247 |         ops.forEach(op => {
2248 |             if (op.action === 'comment') return;
2249 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2250 |             
2251 |             if (op.action === 'replace_block') {
2252 |                 // Strategy 1: Exact String Match (Fastest)
2253 |                 const currentStr = lines.join('\n');
2254 |                 if (currentStr.includes(op.find_block)) {
2255 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2256 |                     logs.push('Exact match applied');
2257 |                     return;
2258 |                 }
2259 | 
2260 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2261 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2262 |                 if (searchLines.length === 0) return;
2263 | 
2264 |                 let matchStart = -1;
2265 |                 let matchEnd = -1;
2266 | 
2267 |                 // Scan file lines
2268 |                 for (let i = 0; i < lines.length; i++) {
2269 |                     // If first line matches (ignoring whitespace)
2270 |                     if (lines[i].trim() === searchLines[0]) {
2271 |                         // Check subsequent lines
2272 |                         let allMatch = true;
2273 |                         let fileOffset = 0;
2274 |                         let searchOffset = 1;
2275 |                         
2276 |                         while (searchOffset < searchLines.length) {
2277 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2278 |                             const nextFile = lines[i + fileOffset + 1].trim();
2279 |                             // Skip empty lines in file if they aren't in search block
2280 |                             if (nextFile === '') {
2281 |                                 fileOffset++;
2282 |                                 continue;
2283 |                             }
2284 |                             if (nextFile !== searchLines[searchOffset]) {
2285 |                                 allMatch = false;
2286 |                                 break;
2287 |                             }
2288 |                             fileOffset++;
2289 |                             searchOffset++;
2290 |                         }
2291 | 
2292 |                         if (allMatch) {
2293 |                             matchStart = i;
2294 |                             matchEnd = i + fileOffset;
2295 |                             break;
2296 |                         }
2297 |                     }
2298 |                 }
2299 | 
2300 |                 if (matchStart !== -1) {
2301 |                     // Replace the range of lines
2302 |                     const replacement = op.replace_with.split('\n');
2303 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2304 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2305 |                 } else {
2306 |                     success = false;
2307 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2308 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2309 |                 }
2310 |             }
2311 |         });
2312 |         return { content: lines.join('\n'), success, logs };
2313 |     }
