5128 |         if (seconds < 10) return 'just now';
5129 |         if (seconds < 60) return seconds + 's ago';
5130 |         const minutes = Math.floor(seconds / 60);
5131 |         if (minutes < 60) return minutes + 'm ago';
5132 |         const hours = Math.floor(minutes / 60);
5133 |         if (hours < 24) return hours + 'h ago';
5134 |         return date.toLocaleDateString();
