5337 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5338 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5339 |         
5340 |         const navItems = document.querySelectorAll('.nav-item');
5341 |         switchTab(tabId, navItems[navIndex]);
5342 | 
5343 |         const scrollContainer = document.querySelector('.main-view');
5344 |         let retryCount = 0;
5345 |         const MAX_RETRIES = 5;
5346 | 
5347 |         const attemptNavigation = async () => {
5348 |             const element = document.querySelector(selector);
5349 |             
5350 |             if (element) {
5351 |                 console.log("[DeepJump] Element found. Scrolling...");
5352 |                 
5353 |                 // Wait for any tab transition animations
5354 |                 await new Promise(r => setTimeout(r, 300));
5355 | 
5356 |                 let offsetTop = 0;
5357 |                 let curr = element;
5358 |                 while (curr && curr !== scrollContainer) {
5359 |                     offsetTop += curr.offsetTop;
5360 |                     curr = curr.offsetParent;
5361 |                 }
5362 | 
5363 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5364 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5365 | 
5366 |                 // Visual Highlight
5367 |                 element.style.transition = 'all 0.5s ease';
5368 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5369 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5370 |                 setTimeout(() => {
5371 |                     element.style.backgroundColor = '';
5372 |                     element.style.boxShadow = '';
5373 |                 }, 3000);
5374 |                 
5375 |                 console.groupEnd();
5376 |                 return true;
5377 |             }
5378 | 
5379 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5380 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5381 |                 retryCount++;
5382 |                 showGlobalToast("🔍 Searching deeper...");
5383 |                 
5384 |                 await loadMoreFn(); 
5385 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5386 |                 return attemptNavigation();
5387 |             }
5388 | 
5389 |             console.error("[DeepJump] Failed: Element not found after retries.");
5390 |             showGlobalToast("Entry not found in recent history.", true);
5391 |             console.groupEnd();
5392 |             return false;
5393 |         };
5394 | 
5395 |         setTimeout(attemptNavigation, 100);
5396 |     }
