5750 |         report += `Scope: Last ${selected.length} entries\n\n`;
5751 |         
5752 |         selected.forEach((entry, idx) => {
5753 |             report += `### ${idx + 1}. ${entry.title.replace(/\[Auto-Fix\]/g, '🤖')}\n`;
5754 |             report += `- **Time**: ${new Date(entry.created_at).toLocaleString()}\n`;
5755 |             if (entry.sha) report += `- **Commit**: \`${entry.sha.substring(0, 7)}\`\n`;
5756 |             if (entry.note) report += `- **Note**: ${entry.note}\n`;
5757 |             
