7677 |     function extractTableNames(sql) {
7678 |         if (!sql) return [];
7679 |         const tables = [];
7680 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7681 |         
7682 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7683 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7684 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7685 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7686 | 
7687 |         let match;
7688 |         while ((match = fromRegex.exec(sql)) !== null) {
7689 |             const name = match[1];
7690 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7691 |                 tables.push(name);
7692 |             }
7693 |         }
7694 |         
7695 |         while ((match = metaRegex.exec(sql)) !== null) {
7696 |             const name = match[1];
7697 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7698 |                 tables.push(name);
7699 |             }
